class Solution:
    def binaryGap(self, n: int) -> int:
        b = bin(n)[2:]
        max_gap = 0
        prev_one = -1
        for i, c in enumerate(b):
            if c == '1':
                if prev_one != -1:
                    max_gap = max(max_gap, i - prev_one)
                prev_one = i
        return max_gap

